import{_ as t,o as a,c as d,a2 as l}from"./chunks/framework.CH-YxFqP.js";const s="/nginx-reverse-emby/screenshots/panel-login.png",o="/nginx-reverse-emby/screenshots/panel-http-rules.png",i="/nginx-reverse-emby/screenshots/panel-http-rule-form.png",g=JSON.parse('{"title":"添加 HTTP 规则代理 Emby/Jellyfin","description":"","frontmatter":{},"headers":[],"relativePath":"guide/http-rule.md","filePath":"guide/http-rule.md","lastUpdated":1781350447000}'),n={name:"guide/http-rule.md"};function p(r,e,c,h,m,b){return a(),d("div",null,[...e[0]||(e[0]=[l(`<h1 id="添加-http-规则代理-emby-jellyfin" tabindex="-1">添加 HTTP 规则代理 Emby/Jellyfin <a class="header-anchor" href="#添加-http-规则代理-emby-jellyfin" aria-label="Permalink to &quot;添加 HTTP 规则代理 Emby/Jellyfin&quot;">​</a></h1><p>这篇教程假设你已经完成 Docker Compose 部署，并能打开面板。</p><p>目标是给公费服/公益服 Emby 做一个自己的加速入口：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你自己访问: http://emby.example.com</span></span>
<span class="line"><span>VPS 代理到: https://origin.emby.example.net</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>其中 <code>emby.example.com</code> 换成解析到你 VPS 的域名，<code>origin.emby.example.net</code> 换成公费服/公益服给你的原始 Emby/Jellyfin 地址。</p><p>这个配置解决的是“源站访问慢、绕路、必须挂梯子才能看”的问题。你的播放器以后访问自己的 VPS 域名，由 VPS 去连接源站。</p><h2 id="_1-登录面板" tabindex="-1">1. 登录面板 <a class="header-anchor" href="#_1-登录面板" aria-label="Permalink to &quot;1. 登录面板&quot;">​</a></h2><p>打开：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://&lt;服务器 IP&gt;:8080</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>输入你在 <code>docker-compose.yaml</code> 里设置的 <code>API_TOKEN</code>。</p><p><img src="`+s+'" alt="登录面板"></p><h2 id="_2-进入-http-规则页面" tabindex="-1">2. 进入 HTTP 规则页面 <a class="header-anchor" href="#_2-进入-http-规则页面" aria-label="Permalink to &quot;2. 进入 HTTP 规则页面&quot;">​</a></h2><p>登录后，在左侧导航中进入 <strong>HTTP 规则</strong>。如果页面顶部有节点选择，先选择 <code>local</code> 或你要承载代理规则的 VPS 节点。</p><p><img src="'+o+'" alt="HTTP 规则页面"></p><h2 id="_3-点击添加规则" tabindex="-1">3. 点击添加规则 <a class="header-anchor" href="#_3-点击添加规则" aria-label="Permalink to &quot;3. 点击添加规则&quot;">​</a></h2><p>点击右上角 <strong>添加规则</strong>。</p><p>在弹窗的 <strong>基础配置</strong> 里，只需要先填两个核心字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>示例</th><th>怎么填</th></tr></thead><tbody><tr><td>前端访问地址</td><td><code>emby.example.com</code></td><td>选择 <code>http://</code> 或 <code>https://</code>，右侧填你自己的加速入口域名。</td></tr><tr><td>后端服务器</td><td><code>origin.emby.example.net</code></td><td>选择源站实际协议，右侧填公费服/公益服给你的 Emby 原始域名和端口。</td></tr></tbody></table><p><img src="'+i+'" alt="添加 HTTP 规则"></p><h2 id="_4-保持规则启用并保存" tabindex="-1">4. 保持规则启用并保存 <a class="header-anchor" href="#_4-保持规则启用并保存" aria-label="Permalink to &quot;4. 保持规则启用并保存&quot;">​</a></h2><p>保持 <strong>启用此规则</strong> 开启，然后点击 <strong>创建规则</strong>。</p><p>保存后回到 HTTP 规则列表，能看到新规则就表示面板已经记录成功。<code>local</code> agent 会按心跳同步配置并开始监听。</p><h2 id="_5-配好-dns-和端口" tabindex="-1">5. 配好 DNS 和端口 <a class="header-anchor" href="#_5-配好-dns-和端口" aria-label="Permalink to &quot;5. 配好 DNS 和端口&quot;">​</a></h2><p>规则保存后，还需要确认外部访问条件：</p><ul><li><code>emby.example.com</code> 已解析到运行 Nginx-Reverse-Emby 的服务器公网 IP。</li><li>服务器安全组和防火墙已放行访问端口。</li><li>如果使用 <code>http://</code>，通常需要放行 <code>80</code> 或你填写的端口。</li><li>如果使用 <code>https://</code>，通常需要放行 <code>443</code>，并先配置证书。</li><li>源站地址 <code>origin.emby.example.net</code> 必须能从这台 VPS 访问。</li><li>如果源站本身需要登录、邀请码或 Emby 账号，这些仍然按源站规则处理，反代不会绕过权限。</li></ul><h2 id="_6-如果要用-https" tabindex="-1">6. 如果要用 HTTPS <a class="header-anchor" href="#_6-如果要用-https" aria-label="Permalink to &quot;6. 如果要用 HTTPS&quot;">​</a></h2><p>新手优先使用 HTTP-01 自动签证书，不需要配置 Cloudflare Token。</p><p>把前端访问地址改成：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://emby.example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>然后确认这三件事：</p><ul><li><code>emby.example.com</code> 已解析到这台 VPS。</li><li>VPS 的 <code>80</code> 和 <code>443</code> 端口都已放行。</li><li>HTTP 规则保存后，等待本地 Agent 同步并自动申请证书。</li></ul><p>HTTP-01 会临时占用 <code>80</code> 端口完成域名验证。验证通过后，你就可以用 <code>https://emby.example.com</code> 访问自己的 Emby/Jellyfin 入口。</p><p>如果你的 VPS 不能开放 <code>80</code> 端口，或者要申请通配符证书，再去看 <a href="./../reference/certificates">证书管理</a> 里的 DNS 验证。</p><h2 id="_7-浏览器验证" tabindex="-1">7. 浏览器验证 <a class="header-anchor" href="#_7-浏览器验证" aria-label="Permalink to &quot;7. 浏览器验证&quot;">​</a></h2><p>在浏览器打开你的前端访问地址：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://emby.example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果能看到 Emby/Jellyfin 页面，就说明 HTTP 规则已经生效。</p><h2 id="流式恢复说明" tabindex="-1">流式恢复说明 <a class="header-anchor" href="#流式恢复说明" aria-label="Permalink to &quot;流式恢复说明&quot;">​</a></h2><p>HTTP 规则内置中断流恢复和同 backend 的安全重试，用来改善大文件播放时的偶发断流。它不会绕过源站权限，也不会把不稳定或不可达的源站变成可用源站。</p><p>中断恢复主要覆盖：</p><ul><li><code>GET</code> 全量响应。</li><li><code>GET</code> 单区间 <code>Range</code> 响应。</li></ul><p>源站需要持续支持 <code>Accept-Ranges: bytes</code>，并返回稳定的强 <code>ETag</code> 或 <code>Last-Modified</code>。如果源站校验器或 <code>Content-Range</code> 不一致，恢复会停止并返回错误。</p><p>如果打不开，按这个顺序排查：</p><ol><li>域名是否解析到正确服务器。</li><li>服务器端口是否放行。</li><li>VPS 是否能访问公费服/公益服源站。</li><li>HTTP 规则是否选择了正确 Agent。</li><li>规则是否保持启用。</li><li>源站是否限制 Host、地区、IP 或需要特殊路径。</li></ol><h2 id="常见填写错误" tabindex="-1">常见填写错误 <a class="header-anchor" href="#常见填写错误" aria-label="Permalink to &quot;常见填写错误&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>常见原因</th></tr></thead><tbody><tr><td>打开域名没反应</td><td>DNS 没生效，或端口没放行。</td></tr><tr><td>面板里规则保存了，但访问不到源站</td><td>VPS 无法访问公费服/公益服源站，或源站协议、端口填错。</td></tr><tr><td>用 HTTPS 访问失败</td><td>还没有配置证书，先用 HTTP 验证规则，确认代理链路正常后再启用 HTTPS。</td></tr><tr><td>登录页能打开但播放失败</td><td>源站线路到 VPS 不稳定、源站限制反代，或播放器仍在请求源站直链。</td></tr><tr><td>代理到错误服务</td><td>前端访问地址或后端服务器填错，检查协议、域名、端口。</td></tr></tbody></table>',46)])])}const T=t(n,[["render",p]]);export{g as __pageData,T as default};
